module adder_16bit
(
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);
    wire [7:0] sum_low, sum_high;
    wire Co_low, Co_high;

    assign {Co_low, sum_low} = a[7:0] + b[7:0] + Cin;
    assign {Co_high, sum_high} = a[15:8] + b[15:8] + Co_low;

    assign y = {sum_high, sum_low};
    assign Co = Co_high;
endmodule
